{
    "level": "A1–A2",
    "intro": "In this topic you will learn <strong>imperatives</strong> (imperatives): how to give orders, requests, advice and instructions in English.",
    "rules": [
        {
            "label": "Affirmative",
            "color": "emerald",
            "text": "<strong>Affirmative form</strong> — begins with verbs:",
            "example": "Sit down. / Open the door."
        },
        {
            "label": "Negative",
            "color": "rose",
            "text": "<strong>Negative form</strong> — Don't + verb:",
            "example": "Don't open it. / Don't be late."
        },
        {
            "label": "Polite",
            "color": "blue",
            "text": "<strong>Polite form</strong> — with Please:",
            "example": "Please sit down. / Close the door, please."
        }
    ]
}

{
    "title": "1. What is an imperative sentence?",
    "intro": "An imperative sentence is a sentence that expresses:",
    "items": [
        {
            "label": "Command",
            "title": "Order",
            "subtitle": "Stop! / Be quiet! / Leave now!"
        },
        {
            "label": "Request",
            "title": "Request",
            "subtitle": "Please help me. / Pass the salt, please."
        },
        {
            "label": "Advice",
            "title": "Advice",
            "subtitle": "Take an umbrella. / Get some rest."
        },
        {
            "label": "Instruction",
            "title": "Instruction",
            "subtitle": "Turn left. / Press the button."
        },
        {
            "label": "Warning",
            "title": "Warning",
            "subtitle": "Be careful! / Watch out!"
        },
        {
            "label": "Invitation",
            "title": "Invitation",
            "subtitle": "Come in! / Have a seat."
        }
    ]
}

{
    "title": "2. The structure of an imperative sentence",
    "sections": [
        {
            "label": "Basic structure",
            "color": "emerald",
            "description": "An imperative sentence begins with a <strong>verb in the basic form</strong> (without to). Subject (you) is <strong>not used</strong>.",
            "examples": [
                {
                    "en": "Sit down.",
                    "ua": "Sit down."
                },
                {
                    "en": "Open the window.",
                    "ua": "Open the window."
                },
                {
                    "en": "Listen to me.",
                    "ua": " me."
                }
            ]
        },
        {
            "label": "No subject",
            "color": "sky",
            "description": "Unlike other sentences, the imperative <strong>has no subject</strong>. The subject (you) is implied.",
            "examples": [
                {
                    "en": "(You) Close the door.",
                    "ua": "(You) Close the door."
                },
                {
                    "en": "(You) Be quiet.",
                    "ua": "(You) Be quiet."
                },
                {
                    "en": "(You) Come here.",
                    "ua": "(You) Come here."
                }
            ],
            "note": "The subject <strong>you</strong> is sometimes used for emphasis or contrast: <em>You sit here, and you sit there.</em>"
        }
    ]
}

{
    "title": "3. Affirmative",
    "sections": [
        {
            "label": "Structure: Verb + Object",
            "color": "emerald",
            "description": "Affirmative imperative sentence: <strong>verb + object</strong>.",
            "examples": [
                {
                    "en": "Open the door.",
                    "ua": "Open the door."
                },
                {
                    "en": "Read this book.",
                    "ua": "Read this book."
                },
                {
                    "en": "Write your name.",
                    "ua": "Write your name."
                },
                {
                    "en": "Call me tomorrow.",
                    "ua": "Call me tomorrow."
                }
            ]
        },
        {
            "label": "Without attachment",
            "color": "sky",
            "description": "Some imperative sentences consist only of verbs.",
            "examples": [
                {
                    "en": "Stop!",
                    "ua": "Stop!"
                },
                {
                    "en": "Wait!",
                    "ua": "Wait!"
                },
                {
                    "en": "Listen!",
                    "ua": "Listen!"
                },
                {
                    "en": "Run!",
                    "ua": "Run!"
                }
            ]
        },
        {
            "label": "With the verb BE",
            "color": "amber",
            "description": "With the verb <strong>be</strong> we use the base form.",
            "examples": [
                {
                    "en": "Be careful!",
                    "ua": "Be careful!"
                },
                {
                    "en": "Be quiet.",
                    "ua": "Be quiet."
                },
                {
                    "en": "Be patient.",
                    "ua": "Be patient."
                },
                {
                    "en": "Be on time.",
                    "ua": "Be on time."
                }
            ]
        }
    ]
}

{
    "title": "4. Negative form (Negative) - Don't",
    "sections": [
        {
            "label": "Structure: Don't + Verb",
            "color": "rose",
            "description": "The negative form is formed by <strong>Don't (Do not)</strong> before the verb.",
            "examples": [
                {
                    "en": "Don't open it.",
                    "ua": "Don't open it this."
                },
                {
                    "en": "Don't touch that.",
                    "ua": "Don't touch that."
                },
                {
                    "en": "Don't forget your keys.",
                    "ua": "Don't forget your keys."
                },
                {
                    "en": "Don't worry.",
                    "ua": "No worry."
                }
            ]
        },
        {
            "label": "Don't be...",
            "color": "sky",
            "description": "With the verb <strong>be</strong>: <strong>Don't be</strong> + adjective/noun.",
            "examples": [
                {
                    "en": "Don't be late.",
                    "ua": "Don't be late."
                },
                {
                    "en": "Don't be silly.",
                    "ua": "Don't be stupid."
                },
                {
                    "en": "Don't be afraid.",
                    "ua": "Don't be afraid."
                },
                {
                    "en": "Don't be rude.",
                    "ua": "Don't be rude."
                }
            ]
        },
        {
            "label": "Full form",
            "color": "amber",
            "description": "In a formal style, use the full form <strong>Do not</strong>.",
            "examples": [
                {
                    "en": "Do not enter.",
                    "ua": "Do not enter. (on signs)"
                },
                {
                    "en": "Do not disturb.",
                    "ua": "Do not disturb."
                },
                {
                    "en": "Do not smoke.",
                    "ua": "Do not smoke."
                }
            ],
            "note": "<strong>Do not</strong> is more often found on signs, instructions and official documents."
        }
    ]
}

{
    "title": "5. Polite Forms",
    "sections": [
        {
            "label": "Please",
            "color": "emerald",
            "description": "Adding <strong>please</strong> makes the command more polite. Can stand at the beginning or at the end.",
            "examples": [
                {
                    "en": "Please sit down.",
                    "ua": "Please sit down."
                },
                {
                    "en": "Close the door, please.",
                    "ua": "Close the door, please."
                },
                {
                    "en": "Please be quiet.",
                    "ua": "Please be quiet quietly."
                },
                {
                    "en": "Help me, please.",
                    "ua": "Help me, please."
                }
            ]
        },
        {
            "label": "Let's is for a group",
            "color": "sky",
            "description": "<strong>Let's</strong> (Let us) is used for suggestions when the speaker includes himself.",
            "examples": [
                {
                    "en": "Let's go!",
                    "ua": "Let's go!"
                },
                {
                    "en": "Let's start.",
                    "ua": "Let's start."
                },
                {
                    "en": "Let's have lunch.",
                    "ua": "Let's have lunch."
                },
                {
                    "en": "Let's not argue.",
                    "ua": "Let's not argue."
                }
            ]
        },
        {
            "label": "Alternative forms",
            "color": "amber",
            "description": "Even more polite ways to express a request:",
            "examples": [
                {
                    "en": "Could you open the window? mind closing the door?",
                    "ua": "Не міг би ти відчинити вікно?"
                },
                {
                    "en": "Would you mind closing the door?",
                    "ua": "Do you mind closing the door?"
                },
                {
                    "en": "Can you help me, please?",
                    "ua": "Can you help me, please?"
                }
            ],
            "note": "These forms are questions but function as polite requests."
        }
    ]
}

{
    "title": "6. Use of imperative sentences",
    "sections": [
        {
            "label": "Orders and commands",
            "color": "emerald",
            "description": "Direct orders from parents, teachers, bosses, etc. Thursday. the corner.",
            "examples": [
                {
                    "en": "Clean your room!",
                    "ua": "Прибери свою кімнату!"
                },
                {
                    "en": "Finish your homework.",
                    "ua": "Закінчи домашнє завдання."
                },
                {
                    "en": "Submit the report by Friday.",
                    "ua": "Здай звіт до пʼятниці."
                }
            ]
        },
        {
            "label": "Інструкції",
            "color": "sky",
            "description": "Покрокові вказівки в рецептах, інструкціях, маршрутах.",
            "examples": [
                {
                    "en": "Mix the flour and eggs.",
                    "ua": "Змішай борошно і яйця."
                },
                {
                    "en": "Turn left at the corner.",
                    "ua": "Turn left at the corner."
                },
                {
                    "en": "Press the green button.",
                    "ua": "Press the green button."
                }
            ]
        },
        {
            "label": "Tips and warnings",
            "color": "amber",
            "description": "Recommendations and warnings.",
            "examples": [
                {
                    "en": "Take an umbrella. It might rain.",
                    "ua": "Take an umbrella. It may rain."
                },
                {
                    "en": "Be careful on the ice!",
                    "ua": "Be careful on the ice!"
                },
                {
                    "en": "Don't eat too much sugar.",
                    "ua": "Don't eat too much sugar."
                }
            ]
        }
    ]
}

{
    "title": "7. Comparison of forms",
    "intro": "Affirmative vs negative form:",
    "rows": [
        {
            "en": "Affirmative",
            "ua": "Affirmative",
            "note": "Sit down. / Open it. / Be quiet."
        },
        {
            "en": "Negative",
            "ua": "Negative",
            "note": "Don't sit. / Don't open it. / Don't be loud."
        },
        {
            "en": "Polite (please)",
            "ua": "Polite",
            "note": "Please sit down. / Sit down, please."
        },
        {
            "en": "Let's (group)",
            "ua": "For the group",
            "note": "Let's sit down. / Let's not argue."
        }
    ],
    "warning": "📌 Formula: <strong>Verb + Object</strong> or <strong>Don't + Verb + Object</strong>"
}

{
    "title": "8. Punctuation: / Close the door. — neutral tone",
    "intro": "Наказові речення можуть закінчуватися:",
    "rows": [
        {
            "en": "Period (.)",
            "ua": "Крапка",
            "note": "Sit down. / Close the door. — нейтральний тон"
        },
        {
            "en": "Exclamation mark (!)",
            "ua": "Exclamation mark",
            "note": "Stop! / Be careful! — strong emotion or urgency"
        }
    ],
    "warning": "⚠️ Use the exclamation mark (!) for urgent commands or warnings."
}

{
    "title": "9. Typical mistakes of Ukrainian speakers",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Adding the subject you.",
            "wrong": "You open the door!",
            "right": "​​​​ <span class="font-mono">Open the door!</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Using No instead of Don't.",
            "wrong": "No touch it!",
            "right": "​​​​​​​​​​​​ sit down!"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Дієслово з to.",
            "wrong": "To sit down!",
            "right": "​​​​​​​​​​ late!</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Don't з be — пропуск be.",
            "wrong": "Don't late!",
            "right": "✅ <span class="font-mono">Don't be late!</span>"
        }
    ]
}

{
    "title": "11. Practice",
    "select_title": "Exercise 1. Choose the correct form",
    "select_intro": "Choose the correct variant of the imperative sentence.",
    "selects": [
        {
            "label": "a) Don't be late. / b) Don't late.",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) You close the door! / b) Close the door!",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) No touch it! / b) Don't touch it!",
            "prompt": "Which option is correct?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Exercise 2. Create a negative form",
    "input_intro": "Turn an affirmative sentence into a negative one (with Don't).",
    "inputs": [
        {
            "before": "Open the window. →",
            "after": ""
        },
        {
            "before": "Be loud. →",
            "after": ""
        },
        {
            "before": "Forget your keys. →",
            "after": ""
        }
    ],
    "rephrase_title": "Exercise 3. Error correction",
    "rephrase_intro": "Find and correct the error in the imperative sentence.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "You sit down!",
            "example_target": "Sit down!"
        },
        {
            "original": "1. To be quiet!",
            "placeholder": "Fix the bug"
        },
        {
            "original": "2. Don't late for class!",
            "placeholder": "Correct a mistake"
        }
    ]
}

